import{_ as r,C as n,o as t,c as i,a2 as a,b as l,w as o,a as c,E as d,a3 as m}from"./chunks/framework.B72_uj9U.js";const q=JSON.parse('{"title":"Memory Systems in Coding Agents","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/context-management/memory-systems.md","filePath":"research/concepts/context-management/memory-systems.md"}'),p={name:"research/concepts/context-management/memory-systems.md"};function h(u,e,g,y,f,b){const s=n("Mermaid");return t(),i("div",null,[e[1]||(e[1]=a(`<h1 id="memory-systems-in-coding-agents" tabindex="-1">Memory Systems in Coding Agents <a class="header-anchor" href="#memory-systems-in-coding-agents" aria-label="Permalink to &quot;Memory Systems in Coding Agents&quot;">​</a></h1><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Memory in coding agents refers to persistent information that survives across sessions and context compaction events. Unlike raw conversation history, memory is curated, structured, and deliberately maintained — it represents what the agent (or its human operator) has decided is worth retaining.</p><p>When a context window fills up, older messages get compacted or dropped. Memory persists through these events — either by being re-injected after compaction or by living outside the context window entirely and being retrieved on demand.</p><p>Two broad categories of memory exist in modern coding agents:</p><ol><li><p><strong>Explicit memory files</strong> — human-authored instruction files that tell the agent about the project. Examples: CLAUDE.md, .goosehints, AGENTS.md, GEMINI.md. Version-controlled, shared across team members, representing institutional knowledge.</p></li><li><p><strong>Auto-memory</strong> — agent-maintained memory created and updated based on learned interactions. Examples: Claude Code&#39;s MEMORY.md, Letta/MemGPT&#39;s archival memory, Mem0&#39;s extracted facts. Typically machine-local, personalized, evolving over time.</p></li></ol><hr><h2 id="_2-claude-md-claude-code" tabindex="-1">2. CLAUDE.md (Claude Code) <a class="header-anchor" href="#_2-claude-md-claude-code" aria-label="Permalink to &quot;2. CLAUDE.md (Claude Code)&quot;">​</a></h2><p>CLAUDE.md is Claude Code&#39;s project-level instruction file, loaded at session start. It serves as persistent project context the agent relies on regardless of conversation state.</p><h3 id="hierarchical-loading" tabindex="-1">Hierarchical Loading <a class="header-anchor" href="#hierarchical-loading" aria-label="Permalink to &quot;Hierarchical Loading&quot;">​</a></h3><p>CLAUDE.md files load in a specific hierarchy, with later files taking precedence:</p><ol><li><strong>User-level</strong> (<code>~/.claude/CLAUDE.md</code>) — personal preferences and global conventions</li><li><strong>Parent directories</strong> — walking up from project root toward filesystem root</li><li><strong>Project root</strong> (<code>./CLAUDE.md</code>) — primary project-level instructions</li><li><strong>Child directories</strong> (JIT discovery) — loaded only when agent accesses files in those subdirectories</li></ol><h3 id="jit-just-in-time-discovery" tabindex="-1">JIT (Just-In-Time) Discovery <a class="header-anchor" href="#jit-just-in-time-discovery" aria-label="Permalink to &quot;JIT (Just-In-Time) Discovery&quot;">​</a></h3><p>Child directory CLAUDE.md files are NOT loaded at startup. They are discovered just-in-time when the agent first touches a file in that directory. In a large monorepo with dozens of subdirectories, this keeps initial token usage low while allowing directory-specific instructions.</p><h3 id="modular-imports" tabindex="-1">Modular Imports <a class="header-anchor" href="#modular-imports" aria-label="Permalink to &quot;Modular Imports&quot;">​</a></h3><p>CLAUDE.md supports importing other files via <code>@path/to/file</code> syntax:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;"># Project Guidelines</span></span>
<span class="line"><span style="color:#CDD6F4;">@docs/api-spec.md</span></span>
<span class="line"><span style="color:#CDD6F4;">@docs/database-schema.md</span></span></code></pre></div><p>Referenced files are loaded and included in context, enabling modular documentation.</p><h3 id="compaction-survival" tabindex="-1">Compaction Survival <a class="header-anchor" href="#compaction-survival" aria-label="Permalink to &quot;Compaction Survival&quot;">​</a></h3><p>CLAUDE.md content survives context compaction. When the context window fills up and older messages are compressed, CLAUDE.md is re-read from disk and re-injected. Project instructions are never lost, even in very long sessions.</p><h3 id="what-goes-in-claude-md" tabindex="-1">What Goes in CLAUDE.md <a class="header-anchor" href="#what-goes-in-claude-md" aria-label="Permalink to &quot;What Goes in CLAUDE.md&quot;">​</a></h3><ul><li><strong>Project conventions</strong>: coding style, naming patterns, architectural decisions</li><li><strong>Build/test commands</strong>: exact commands to build, test, lint, deploy</li><li><strong>Architecture overview</strong>: directory structure, key modules, data flow</li><li><strong>Files to avoid</strong>: generated files, migrations, vendor directories</li><li><strong>Common gotchas</strong>: known issues, non-obvious behaviors</li></ul><h3 id="example-claude-md" tabindex="-1">Example CLAUDE.md <a class="header-anchor" href="#example-claude-md" aria-label="Permalink to &quot;Example CLAUDE.md&quot;">​</a></h3><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;"># Project Guidelines</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Build &amp; Test</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Run tests with: npm test</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Lint with: npm run lint</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Type check: npx tsc --noEmit</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Architecture</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> src/api/ — Express route handlers</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> src/services/ — Business logic layer</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> src/models/ — Prisma schema and generated client</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Conventions</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Use TypeScript strict mode</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Prefer named exports over default exports</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Error handling: use Result&lt;T, E&gt; pattern, not try/catch</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## Warnings</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Never modify migration files directly — use </span><span style="color:#A6E3A1;">\`prisma migrate dev\`</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> @docs/api-spec.md for API specification</span></span></code></pre></div><hr><h2 id="_3-auto-memory-claude-code" tabindex="-1">3. Auto-Memory (Claude Code) <a class="header-anchor" href="#_3-auto-memory-claude-code" aria-label="Permalink to &quot;3. Auto-Memory (Claude Code)&quot;">​</a></h2><p>Beyond human-authored CLAUDE.md files, Claude Code maintains its own autonomous memory.</p><h3 id="storage-and-loading" tabindex="-1">Storage and Loading <a class="header-anchor" href="#storage-and-loading" aria-label="Permalink to &quot;Storage and Loading&quot;">​</a></h3><p>Auto-memory is stored at <code>~/.claude/projects/&lt;project-hash&gt;/memory/MEMORY.md</code>. This is machine-local and NOT committed to the repository. Only the first 200 lines are loaded at startup — a practical token budget threshold that forces the agent to be selective.</p><h3 id="what-gets-auto-remembered" tabindex="-1">What Gets Auto-Remembered <a class="header-anchor" href="#what-gets-auto-remembered" aria-label="Permalink to &quot;What Gets Auto-Remembered&quot;">​</a></h3><ul><li><strong>User preferences</strong> discovered during conversation (&quot;user prefers functional style&quot;)</li><li><strong>Project patterns</strong> learned through exploration (&quot;tests use vitest, not jest&quot;)</li><li><strong>Common workflows</strong> the user repeats (&quot;always run lint before committing&quot;)</li><li><strong>Error patterns and solutions</strong> (&quot;prisma generate must run after schema changes&quot;)</li></ul><h3 id="machine-local-nature" tabindex="-1">Machine-Local Nature <a class="header-anchor" href="#machine-local-nature" aria-label="Permalink to &quot;Machine-Local Nature&quot;">​</a></h3><p>Each developer accumulates their own memory. This is intentional — auto-memory captures personal preferences and local environment quirks. Shared knowledge belongs in CLAUDE.md; personal knowledge belongs in auto-memory.</p><hr><h2 id="_4-goosehints-goose" tabindex="-1">4. GooseHints (Goose) <a class="header-anchor" href="#_4-goosehints-goose" aria-label="Permalink to &quot;4. GooseHints (Goose)&quot;">​</a></h2><p>Goose uses <code>.goosehints</code> files at the project root for agent guidance.</p><ul><li>Contains project hints: build commands, conventions, warnings, architecture notes</li><li>Format is flexible — plain text or markdown</li><li>Injected into agent context at session start</li><li>Also reads <code>AGENTS.md</code> files for cross-agent compatibility</li><li>Follows global → project → directory hierarchy</li></ul><hr><h2 id="_5-agents-md-forgecode-warp" tabindex="-1">5. AGENTS.md (ForgeCode, Warp) <a class="header-anchor" href="#_5-agents-md-forgecode-warp" aria-label="Permalink to &quot;5. AGENTS.md (ForgeCode, Warp)&quot;">​</a></h2><p>AGENTS.md is an agent configuration file used by multiple tools, notably ForgeCode and Warp.</p><h3 id="warp-s-hierarchy" tabindex="-1">Warp&#39;s Hierarchy <a class="header-anchor" href="#warp-s-hierarchy" aria-label="Permalink to &quot;Warp&#39;s Hierarchy&quot;">​</a></h3><ul><li><strong>Global</strong> — organization or user-level defaults</li><li><strong>Project</strong> — project root AGENTS.md</li><li><strong>Directory</strong> — subdirectory-specific overrides</li></ul><h3 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h3><ul><li>Technology stack description (languages, frameworks, versions)</li><li>File organization and directory structure conventions</li><li>Build, test, lint, and deployment commands</li><li>Testing patterns and coverage requirements</li><li>Deployment notes and environment variables</li><li>Warnings about security-sensitive or fragile areas</li></ul><p>ForgeCode uses AGENTS.md for bounded context guidance — helping the agent understand project scope and constraints without discovering everything from scratch.</p><hr><h2 id="_6-gemini-md-gemini-cli" tabindex="-1">6. GEMINI.md (Gemini CLI) <a class="header-anchor" href="#_6-gemini-md-gemini-cli" aria-label="Permalink to &quot;6. GEMINI.md (Gemini CLI)&quot;">​</a></h2><p>GEMINI.md serves the same purpose as CLAUDE.md but for Google&#39;s Gemini CLI agent.</p><ul><li><strong>Global</strong> (<code>~/.gemini/GEMINI.md</code>) → <strong>workspace</strong> (project root) → <strong>JIT discovery</strong> (subdirectories)</li><li>Supports <code>@path/to/file</code> imports for modular documentation</li><li>Survives compaction by re-reading from disk after context compression</li></ul><p>The convergence of CLAUDE.md, GEMINI.md, and AGENTS.md toward similar hierarchical, file-based memory systems suggests this pattern is becoming a de facto standard.</p><hr><h2 id="_7-moim-goose-s-model-oriented-information-management" tabindex="-1">7. MOIM: Goose&#39;s Model-Oriented Information Management <a class="header-anchor" href="#_7-moim-goose-s-model-oriented-information-management" aria-label="Permalink to &quot;7. MOIM: Goose&#39;s Model-Oriented Information Management&quot;">​</a></h2><p>Goose implements a dynamic memory injection system (MOIM) that differs from static file-based approaches.</p><h3 id="per-turn-injection" tabindex="-1">Per-Turn Injection <a class="header-anchor" href="#per-turn-injection" aria-label="Permalink to &quot;Per-Turn Injection&quot;">​</a></h3><p>Each turn, before calling the LLM, Goose runs <code>inject_moim()</code> — collecting context from all active extensions and injecting it into the prompt. The context available to the model can change on every single turn.</p><h3 id="extension-driven-context" tabindex="-1">Extension-Driven Context <a class="header-anchor" href="#extension-driven-context" aria-label="Permalink to &quot;Extension-Driven Context&quot;">​</a></h3><p>MOIM is driven by Goose&#39;s extension ecosystem. Each extension provides per-turn context it determines is relevant RIGHT NOW. Conceptually similar to RAG, but instead of searching a vector store, context is provided by active extensions based on their own logic.</p><h3 id="top-of-mind-extension" tabindex="-1">Top of Mind Extension <a class="header-anchor" href="#top-of-mind-extension" aria-label="Permalink to &quot;Top of Mind Extension&quot;">​</a></h3><p>The &quot;Top of Mind&quot; extension injects persistent user instructions — things the user always wants the agent to consider. This bridges static memory files and dynamic per-turn context.</p><h3 id="dynamic-nature" tabindex="-1">Dynamic Nature <a class="header-anchor" href="#dynamic-nature" aria-label="Permalink to &quot;Dynamic Nature&quot;">​</a></h3><p>Unlike CLAUDE.md (same content every turn), MOIM injects different content each turn based on what extensions determine is relevant. This is dynamic memory that adapts to the agent&#39;s evolving needs within a session.</p><hr><h2 id="_8-letta-memgpt-memory-architecture" tabindex="-1">8. Letta/MemGPT Memory Architecture <a class="header-anchor" href="#_8-letta-memgpt-memory-architecture" aria-label="Permalink to &quot;8. Letta/MemGPT Memory Architecture&quot;">​</a></h2><p>Letta (formerly MemGPT) takes the most radical approach: it treats the context window like RAM in an operating system, giving the agent tools to manage its own memory explicitly.</p><h3 id="the-os-analogy" tabindex="-1">The OS Analogy <a class="header-anchor" href="#the-os-analogy" aria-label="Permalink to &quot;The OS Analogy&quot;">​</a></h3>`,65)),(t(),l(m,null,{default:o(()=>[d(s,{id:"mermaid-329",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20CTX%5B%22Context%20Window%20%3D%20%26quot%3BRAM%26quot%3B%22%5D%0A%20%20%20%20%20%20%20%20SP%5B%22System%20Prompt%20(OS%20kernel)%22%5D%0A%20%20%20%20%20%20%20%20CM%5B%22Core%20Memory%20(working%20set)%22%5D%0A%20%20%20%20%20%20%20%20RM%5B%22Recent%20Messages%20(stack)%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20ARCH%5B%22Archival%20Memory%20%3D%20%26quot%3BDisk%26quot%3B%22%5D%0A%20%20%20%20%20%20%20%20VI%5B%22Vector-indexed%20facts%22%5D%0A%20%20%20%20%20%20%20%20PC%5B%22Past%20conversations%22%5D%0A%20%20%20%20%20%20%20%20UI%5B%22User%20information%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20TOOLS%5B%22Agent%20Tools%20%3D%20%26quot%3BSystem%20Calls%26quot%3B%22%5D%0A%20%20%20%20%20%20%20%20T1%5B%22core_memory_append()%22%5D%0A%20%20%20%20%20%20%20%20T2%5B%22core_memory_replace()%22%5D%0A%20%20%20%20%20%20%20%20T3%5B%22archival_memory_insert()%22%5D%0A%20%20%20%20%20%20%20%20T4%5B%22archival_memory_search()%22%5D%0A%20%20%20%20%20%20%20%20T5%5B%22conversation_search()%22%5D%0A%20%20%20%20end%0A%20%20%20%20CTX%20%3C--%3E%7C%22manage%22%7C%20TOOLS%0A%20%20%20%20ARCH%20%3C--%3E%7C%22insert%20%2F%20search%22%7C%20TOOLS%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a(`<h3 id="memory-types" tabindex="-1">Memory Types <a class="header-anchor" href="#memory-types" aria-label="Permalink to &quot;Memory Types&quot;">​</a></h3><p><strong>Core Memory</strong> — always visible in context, limited to ~2K tokens. Divided into blocks:</p><ul><li><strong>Human block</strong>: information about the user (name, preferences, background)</li><li><strong>Persona block</strong>: agent&#39;s identity, instructions, behavioral guidelines</li></ul><p>Modified via <code>core_memory_append()</code> and <code>core_memory_replace()</code>.</p><p><strong>Archival Memory</strong> — unlimited external storage backed by a vector database. The agent stores and retrieves via <code>archival_memory_insert()</code> and <code>archival_memory_search()</code>. Equivalent to disk storage — vast capacity but requires explicit access.</p><p><strong>Recall Memory</strong> — past conversation turns in searchable format. The agent searches prior conversations using <code>conversation_search()</code>, recalling details from interactions that have long since left the context window.</p><h3 id="self-managed-memory" tabindex="-1">Self-Managed Memory <a class="header-anchor" href="#self-managed-memory" aria-label="Permalink to &quot;Self-Managed Memory&quot;">​</a></h3><p>The agent itself decides what to remember and forget. No external system summarizes conversations — the agent uses memory tools as part of its reasoning. This creates a feedback loop: memory management improves as the model improves.</p><hr><h2 id="_9-short-term-vs-long-term-memory-patterns" tabindex="-1">9. Short-Term vs Long-Term Memory Patterns <a class="header-anchor" href="#_9-short-term-vs-long-term-memory-patterns" aria-label="Permalink to &quot;9. Short-Term vs Long-Term Memory Patterns&quot;">​</a></h2><h3 id="short-term-memory" tabindex="-1">Short-Term Memory <a class="header-anchor" href="#short-term-memory" aria-label="Permalink to &quot;Short-Term Memory&quot;">​</a></h3><ul><li><strong>What</strong>: conversation history, tool results, current task state</li><li><strong>Where</strong>: context window</li><li><strong>Duration</strong>: single session or task; subject to compaction</li></ul><h3 id="medium-term-memory" tabindex="-1">Medium-Term Memory <a class="header-anchor" href="#medium-term-memory" aria-label="Permalink to &quot;Medium-Term Memory&quot;">​</a></h3><ul><li><strong>What</strong>: session summaries, checkpoint states, compacted conversation</li><li><strong>Where</strong>: session storage (SQLite, JSONL)</li><li><strong>Duration</strong>: session lifetime; persists across compactions</li></ul><h3 id="long-term-memory" tabindex="-1">Long-Term Memory <a class="header-anchor" href="#long-term-memory" aria-label="Permalink to &quot;Long-Term Memory&quot;">​</a></h3><ul><li><strong>What</strong>: project knowledge, user preferences, learned patterns</li><li><strong>Where</strong>: files (CLAUDE.md, MEMORY.md), databases, vector stores</li><li><strong>Duration</strong>: project lifetime or beyond</li></ul><h3 id="the-computer-architecture-parallel" tabindex="-1">The Computer Architecture Parallel <a class="header-anchor" href="#the-computer-architecture-parallel" aria-label="Permalink to &quot;The Computer Architecture Parallel&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Computer Architecture</th><th>Agent Memory</th><th>Characteristics</th></tr></thead><tbody><tr><td>Registers</td><td>Current message/turn</td><td>Always available, tiny capacity</td></tr><tr><td>L1 Cache</td><td>Recent messages</td><td>Fast access, frequently evicted</td></tr><tr><td>L2/L3 Cache</td><td>Compaction summaries</td><td>Compressed representation</td></tr><tr><td>RAM</td><td>Context window</td><td>Limited size, everything &quot;visible&quot;</td></tr><tr><td>SSD/Disk</td><td>Persistent files, databases</td><td>Unlimited, requires explicit access</td></tr><tr><td>Network</td><td>External APIs, RAG stores</td><td>Highest latency, virtually unlimited</td></tr></tbody></table><p>This parallel has real design implications — just as computer architects optimize cache hit rates, agent architects must optimize for having the right information in context at the right time.</p><hr><h2 id="_10-mem0-—-self-improving-memory" tabindex="-1">10. Mem0 — Self-Improving Memory <a class="header-anchor" href="#_10-mem0-—-self-improving-memory" aria-label="Permalink to &quot;10. Mem0 — Self-Improving Memory&quot;">​</a></h2><p>Mem0 is a standalone memory layer for any AI application, providing automatic fact extraction and retrieval.</p><h3 id="core-mechanism" tabindex="-1">Core Mechanism <a class="header-anchor" href="#core-mechanism" aria-label="Permalink to &quot;Core Mechanism&quot;">​</a></h3><p>Automatically extracts facts from conversations, deduplicates against existing memories, and resolves conflicts when new information contradicts old. This happens transparently.</p><h3 id="multi-level-memory" tabindex="-1">Multi-Level Memory <a class="header-anchor" href="#multi-level-memory" aria-label="Permalink to &quot;Multi-Level Memory&quot;">​</a></h3><ul><li><strong>User memory</strong>: facts about specific users, persisted across all sessions</li><li><strong>Session memory</strong>: context within a specific conversation session</li><li><strong>Agent memory</strong>: knowledge the agent accumulates about its own patterns</li></ul><h3 id="storage-and-performance" tabindex="-1">Storage and Performance <a class="header-anchor" href="#storage-and-performance" aria-label="Permalink to &quot;Storage and Performance&quot;">​</a></h3><p>Hybrid approach using vector storage (semantic search) and graph storage (relationship tracking). Claims: +26% accuracy over OpenAI Memory, 91% faster, 90% fewer tokens.</p><h3 id="usage-example" tabindex="-1">Usage Example <a class="header-anchor" href="#usage-example" aria-label="Permalink to &quot;Usage Example&quot;">​</a></h3><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> mem0 </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Memory</span></span>
<span class="line"><span style="color:#CDD6F4;">memory </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Memory</span><span style="color:#9399B2;">()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">messages </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#A6E3A1;">&quot;role&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;content&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;I prefer using pytest over unittest&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#A6E3A1;">&quot;role&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;content&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Noted! I&#39;ll use pytest for your projects.&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">memory</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">add</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> user_id</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;user123&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Later, search relevant memories</span></span>
<span class="line"><span style="color:#CDD6F4;">results </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> memory</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">search</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;testing preferences&quot;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> user_id</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;user123&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Returns: [{&quot;memory&quot;: &quot;User prefers pytest over unittest&quot;, &quot;score&quot;: 0.95}]</span></span></code></pre></div><p>License: Apache 2.0.</p><hr><h2 id="_11-zep-—-long-term-memory-store" tabindex="-1">11. Zep — Long-Term Memory Store <a class="header-anchor" href="#_11-zep-—-long-term-memory-store" aria-label="Permalink to &quot;11. Zep — Long-Term Memory Store&quot;">​</a></h2><p>Zep provides a purpose-built memory store for AI assistants.</p><ul><li><strong>Auto-summarization</strong>: compresses conversations as they grow, maintaining bounded representations of long interaction histories</li><li><strong>Named entity extraction</strong>: tracks people, organizations, tools, concepts across sessions</li><li><strong>Temporal awareness</strong>: knows WHEN things happened; handles information that changes over time (&quot;user switched from Jest to Vitest in March&quot;)</li><li><strong>Hybrid search</strong>: vector similarity + metadata filtering for both semantic and structured queries</li><li><strong>Native LangChain integration</strong> for straightforward adoption</li><li>License: Apache 2.0</li></ul><hr><h2 id="_12-comparison-table" tabindex="-1">12. Comparison Table <a class="header-anchor" href="#_12-comparison-table" aria-label="Permalink to &quot;12. Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>System</th><th>Type</th><th>Auto-Extract</th><th>Survives Compaction</th><th>Hierarchy</th><th>Agent-Authored</th><th>Shared (VCS)</th></tr></thead><tbody><tr><td>CLAUDE.md</td><td>File</td><td>No</td><td>Yes (re-read)</td><td>User→parent→root→child</td><td>No</td><td>Yes</td></tr><tr><td>Auto-Memory</td><td>File</td><td>Yes</td><td>Yes (re-read)</td><td>Project-specific</td><td>Yes</td><td>No</td></tr><tr><td>GooseHints</td><td>File</td><td>No</td><td>Session-scoped</td><td>Global→project→dir</td><td>No</td><td>Yes</td></tr><tr><td>AGENTS.md</td><td>File</td><td>No</td><td>Session-scoped</td><td>Global→project→dir</td><td>No</td><td>Yes</td></tr><tr><td>GEMINI.md</td><td>File</td><td>No</td><td>Yes (re-read)</td><td>Global→workspace→JIT</td><td>No</td><td>Yes</td></tr><tr><td>MOIM</td><td>Dynamic</td><td>No</td><td>N/A (per-turn)</td><td>Extension-driven</td><td>No</td><td>No</td></tr><tr><td>Letta/MemGPT</td><td>Agent-managed</td><td>Yes (agent)</td><td>Yes (external)</td><td>Core→archival→recall</td><td>Yes</td><td>No</td></tr><tr><td>Mem0</td><td>Service</td><td>Yes (auto)</td><td>Yes (external)</td><td>User→session→agent</td><td>Partial</td><td>No</td></tr><tr><td>Zep</td><td>Service</td><td>Yes (auto)</td><td>Yes (external)</td><td>Session-based</td><td>No</td><td>No</td></tr></tbody></table><h3 id="key-observations" tabindex="-1">Key Observations <a class="header-anchor" href="#key-observations" aria-label="Permalink to &quot;Key Observations&quot;">​</a></h3><ul><li><strong>File-based systems</strong> are converging on similar hierarchical designs — this works and is becoming standard.</li><li><strong>Agent-authored memory</strong> represents the frontier — more powerful but harder to control.</li><li><strong>External memory services</strong> are framework-agnostic but add operational complexity.</li><li><strong>Dynamic injection</strong> (MOIM) treats memory as per-turn computation, not a static store.</li></ul><hr><h2 id="_13-best-practices" tabindex="-1">13. Best Practices <a class="header-anchor" href="#_13-best-practices" aria-label="Permalink to &quot;13. Best Practices&quot;">​</a></h2><h3 id="layer-multiple-memory-systems" tabindex="-1">Layer Multiple Memory Systems <a class="header-anchor" href="#layer-multiple-memory-systems" aria-label="Permalink to &quot;Layer Multiple Memory Systems&quot;">​</a></h3><p>No single system covers all needs. Combine:</p><ul><li><strong>Human-authored project docs</strong> (CLAUDE.md / AGENTS.md) for shared team knowledge</li><li><strong>Agent-maintained auto-memory</strong> for personal preferences and discovered patterns</li><li><strong>Structured project docs</strong> (@-imported specs, architecture docs) for detail on demand</li></ul><h3 id="respect-token-budgets" tabindex="-1">Respect Token Budgets <a class="header-anchor" href="#respect-token-budgets" aria-label="Permalink to &quot;Respect Token Budgets&quot;">​</a></h3><p>Memory competes with conversation for context space. Keep files concise:</p><ul><li>CLAUDE.md: under 200 lines of high-signal content</li><li>Auto-memory: prune regularly (the 200-line cap exists for a reason)</li><li>Use @-imports to load detailed docs only when needed</li></ul><h3 id="review-auto-memory-periodically" tabindex="-1">Review Auto-Memory Periodically <a class="header-anchor" href="#review-auto-memory-periodically" aria-label="Permalink to &quot;Review Auto-Memory Periodically&quot;">​</a></h3><p>Agent-authored memory accumulates outdated or incorrect information. Review to:</p><ul><li>Remove stale entries (old patterns, deprecated workflows)</li><li>Correct inaccuracies (wrong lessons learned)</li><li>Consolidate redundant entries</li></ul><h3 id="use-structured-formats" tabindex="-1">Use Structured Formats <a class="header-anchor" href="#use-structured-formats" aria-label="Permalink to &quot;Use Structured Formats&quot;">​</a></h3><ul><li>Consistent headings and bullet points</li><li>Explicit commands over prose descriptions</li><li>Code blocks for commands and examples</li></ul><h3 id="separate-shared-vs-personal-knowledge" tabindex="-1">Separate Shared vs Personal Knowledge <a class="header-anchor" href="#separate-shared-vs-personal-knowledge" aria-label="Permalink to &quot;Separate Shared vs Personal Knowledge&quot;">​</a></h3><ul><li><strong>Shared</strong> (conventions, architecture, commands) → version-controlled files in repo</li><li><strong>Personal</strong> (preferences, local environment) → machine-local auto-memory</li></ul><h3 id="design-for-compaction-survival" tabindex="-1">Design for Compaction Survival <a class="header-anchor" href="#design-for-compaction-survival" aria-label="Permalink to &quot;Design for Compaction Survival&quot;">​</a></h3><p>Assume memory content will be the ONLY context after compaction:</p><ul><li>Self-contained instructions (don&#39;t reference conversation history)</li><li>Explicit commands (<code>npm test</code>, not &quot;the usual test command&quot;)</li><li>Complete file paths (<code>src/config/database.ts</code>, not &quot;the config file&quot;)</li></ul><h3 id="start-minimal-grow-deliberately" tabindex="-1">Start Minimal, Grow Deliberately <a class="header-anchor" href="#start-minimal-grow-deliberately" aria-label="Permalink to &quot;Start Minimal, Grow Deliberately&quot;">​</a></h3><p>Begin with build/test/lint commands, top 3-5 conventions, and a one-paragraph architecture overview. Add more as you discover what the agent gets wrong or asks about repeatedly.</p>`,60))])}const A=r(p,[["render",h]]);export{q as __pageData,A as default};
